import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"鸿门剑舞","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/鸿门剑舞.md","filePath":"4.资源分区/6.技艺及称号/武技类/鸿门剑舞.md"}'),d={name:"4.资源分区/6.技艺及称号/武技类/鸿门剑舞.md"};function l(p,a,_,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"鸿门剑舞",tabindex:"-1"},[s("鸿门剑舞 "),e("a",{class:"header-anchor",href:"#鸿门剑舞","aria-label":'Permalink to "鸿门剑舞"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘004A")])])],-1),o('<h1 id="鸿门剑舞-1" tabindex="-1">鸿门剑舞 <a class="header-anchor" href="#鸿门剑舞-1" aria-label="Permalink to &quot;鸿门剑舞&quot;">​</a></h1><p>鸿门剑舞<br> D+1000<br> 这是一种独特的舞剑方式，曾被项庄在鸿门宴上表演给霸王项羽及沛公刘邦。亚父范增指使项庄持剑于席上舞剑助兴，实为趁机试图刺杀刘邦。<br> 鸿门剑舞包含一种独特的攻击技和一种独特的步法，购买时一并获得之。鸿门剑舞必须在手持分类为剑的武器并使用其进行攻击时才能应用。</p><p>步法：这是一种步法，但可以与其他步法一同使用，当你进行一次移动时，你可以先进行一次风度+表达+专业：舞蹈检定，并在此次移动中可以再额外移动等同于检定出目的移动距离。</p><p>攻击技：这是一种攻击技，只有你在应用过步法的那个回合中才能使用，这项攻击技可以与其他攻击技一同使用。在应用这项攻击技时，立即进行一次风度+隐秘+专业：掩饰检定，被攻击者以察言观色检定进行对抗，若对抗失败，则你对其视为具有D级先制，且你的此次攻击附带虚招。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
